  ('locality-1fb53453-moex-00101', 'locality-1fb53453', 'locality-1fb53453-moex-112-51f0585d', 'sub-locality-1fb53453-05', NULL, 'single_choice', '就廠商的短期生產而言，其他條件不變，當固定生產要素的價格上升時：', '["邊際成本線與平均總成本線都不變", "邊際成本線上移，平均總成本線不變", "邊際成本線不變，平均總成本線上移", "邊際成本線與平均總成本線都上移"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "0827882f64ba", "answer_pdf_sha1": "46a7f3212c67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "318", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
