  ('locality-1fb53453-moex-00107', 'locality-1fb53453', 'locality-1fb53453-moex-112-51f0585d', 'sub-locality-1fb53453-05', NULL, 'single_choice', '為維護國家財政健全，支應國家發展需要，政府得發行公債。根據公債法第2條之規定，我國公 共債務之主管機關在中央為：', '["行政院主計總處", "財政部", "行政院", "財政部國庫署"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "0827882f64ba", "answer_pdf_sha1": "46a7f3212c67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "318", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
